deckCss:
  *{box-sizing:border-box}
  html,body{margin:0;padding:0;background:#0E2841}
  :root{
    --bg:#0E2841;--surface:#153350;--surf2:#1C3D5E;--text:#F1F6FB;--muted:#9DB4CA;
    --line:rgba(226,238,249,.12);--line2:rgba(226,238,249,.20);
    --teal:#156082;--orange:#E97132;--green:#196B24;--green2:#4EA72E;--cyan:#0F9ED5;--purple:#A02B93;
    --sans:'Space Grotesk',-apple-system,system-ui,sans-serif;
    --mono:'JetBrains Mono',ui-monospace,SFMono-Regular,monospace;
  }
  @keyframes fpDelta{from{opacity:0;transform:translateY(20px)}to{opacity:1;transform:none}}
  @keyframes fpPanel{from{opacity:0;transform:translateX(54px)}to{opacity:1;transform:none}}
  @keyframes fpPop{from{opacity:0;transform:scale(.66)}to{opacity:1;transform:scale(1)}}
  @keyframes fpDraw{from{stroke-dashoffset:var(--dash,1500)}to{stroke-dashoffset:0}}
  @keyframes fpFade{from{opacity:0}to{opacity:1}}
  @keyframes fpChip{from{opacity:0;transform:translateX(-24px)}to{opacity:1;transform:none}}
  @media (prefers-reduced-motion: no-preference){
    [data-deck-active] .fp-enter{animation:fpDelta .64s cubic-bezier(.2,.8,.2,1) both}
    [data-deck-active] .fp-panel{animation:fpPanel .62s cubic-bezier(.2,.8,.2,1) both}
    [data-deck-active] .fp-pop{animation:fpPop .54s cubic-bezier(.2,1.25,.4,1) both}
    [data-deck-active] .fp-draw{animation:fpDraw 1.2s ease both}
    [data-deck-active] .fp-fade{animation:fpFade .7s ease both}
    [data-deck-active] .fp-chip{animation:fpChip .52s cubic-bezier(.2,.9,.3,1) both}
  }
  [data-motion="off"] .fp-enter,[data-motion="off"] .fp-panel,[data-motion="off"] .fp-pop,
  [data-motion="off"] .fp-draw,[data-motion="off"] .fp-fade,
  [data-motion="off"] .fp-chip{animation:none !important;opacity:1 !important;transform:none !important;stroke-dashoffset:0 !important}

:root{--accent:#0F9ED5}
  .vr-panel{position:absolute;border-radius:16px;background:var(--surface);box-shadow:inset 0 0 0 1.4px var(--line2),0 24px 60px rgba(0,0,0,.45);}
  .vr-head{display:flex;align-items:center;gap:13px;padding:20px 28px;border-bottom:1px solid var(--line);font:500 22px/1 var(--mono);letter-spacing:.16em;color:var(--muted);}
  .vr-bubble{position:absolute;display:flex;gap:16px;align-items:flex-start;}
  .vr-msg{border-radius:16px;padding:16px 24px;font:400 28px/1.3 var(--sans);color:var(--text);background:var(--surf2);box-shadow:inset 0 0 0 1.4px var(--line2);}
  .vr-msg.bot{background:var(--teal);color:#fff;box-shadow:none;}
  .vr-chip{display:inline-flex;align-items:center;gap:12px;padding:13px 20px;border-radius:12px;background:var(--surf2);box-shadow:inset 0 0 0 1.4px var(--line2);font:500 23px/1 var(--mono);color:var(--text);white-space:nowrap;}
  .vr-tag{display:inline-flex;align-items:center;gap:10px;padding:9px 16px;border-radius:999px;background:var(--surf2);box-shadow:inset 0 0 0 1.4px var(--line2);font:500 20px/1 var(--mono);color:var(--muted);white-space:nowrap;}
  .vr-card{position:absolute;border-radius:14px;background:var(--surface);box-shadow:inset 0 0 0 1.4px var(--line2);padding:16px 22px;}
